// WF_SCENE_IMAGE_PROCESSOR / Generate Scene Image
// v5 (2026-05-07): segment-aware. When body.segment_id is present, PATCH scene_segments
// instead of scenes for provenance, and surface segment_id on the output JSON so the
// downstream HTTP nodes can target the correct table.
//
// Routing (unchanged from v4):
//   body.requires_text_rendering === true     -> fal-ai/recraft-v3   ($0.04/img, native text)
//   body.requires_text_rendering === undefined &&
//     image_prompt matches generic safety regex -> fal-ai/recraft-v3   (legacy scenes)
//   body.requires_text_rendering === false    -> fal-ai/flux/schnell ($0.003/img, no text)
//   recraft-v3 error                          -> fal-ai/ideogram-v2  ($0.08/img, fallback)

const { execSync } = require("child_process");
const body = $("Webhook Trigger").first().json.body || {};
const sceneId = body.scene_id;
const sceneNumber = body.scene_number;
const segmentId = body.segment_id || null;          // null when legacy per-scene
const segmentNumber = body.segment_number || null;
if (sceneNumber === undefined || sceneNumber === null) {
  throw new Error("WF_SCENE_IMAGE_PROCESSOR: body.scene_number missing - parent must pass it. Refusing to default to 0.");
}
// Patch C guard: refuse to PATCH scenes table if scene has uses_segments=true but no segment_id was provided.
// This prevents the silent dispatcher-fallback bug from poisoning scene-level data again.
if (!segmentId && body.uses_segments === true) {
  throw new Error("IMG_PROC_GUARD: scene_id " + sceneId + " (scene_number " + sceneNumber + ") has uses_segments=true in payload but no segment_id. Refusing to PATCH scenes table. Caller must pass segment_id.");
}
const paddedNum = sceneNumber.toString().padStart(3, "0");
const topicId = body.topic_id;
const projectId = body.project_id;
const promptIn = (body.image_prompt || "").toString();
const negativePrompt = body.negative_prompt || "";
const requiresTextFlag = body.requires_text_rendering;

// Generic safety net - only used when the flag is undefined entirely.
const SAFETY_REGEX = /\b(chart|graph|infographic|spreadsheet|dashboard|interface|app interface|web page|webpage|website|screenshot|monitor showing|screen showing|computer screen|laptop screen|tablet showing|phone screen|app screen|document|application form|tax form|tax document|government letter|official document|contract|invoice|receipt|statement|menu|book cover|magazine cover|newspaper|headline|advertisement|advert|billboard|signage|sign reading|poster|label|price tag|table showing|comparison|breakdown|statistics|data visualization|infogram)\b/i;

let useTextModel = false;
let routeReason = "";
if (requiresTextFlag === true) {
  useTextModel = true; routeReason = "flag_true";
} else if (requiresTextFlag === false) {
  useTextModel = false; routeReason = "flag_false";
} else {
  const m = SAFETY_REGEX.exec(promptIn);
  if (m) { useTextModel = true; routeReason = "safety_regex:" + m[0]; }
  else   { useTextModel = false; routeReason = "safety_regex_no_match"; }
}

const targetLabel = segmentId ? ("segment " + sceneNumber + "." + segmentNumber) : ("scene " + sceneNumber);
console.log("[" + targetLabel + "] requires_text_flag=" + JSON.stringify(requiresTextFlag) + " route=" + routeReason + " useTextModel=" + useTextModel + " promptLen=" + promptIn.length);

let modelUsed = "";
let imageUrl = "";
let costUsd = 0;
let providerError = null;
const startTime = Date.now();

async function callFal(endpoint, payload, maxRetries) {
  const retries = maxRetries === undefined ? 3 : maxRetries;
  for (let attempt = 1; attempt <= retries; attempt++) {
    const resp = await fetch(endpoint, {
      method: "POST",
      headers: { "Authorization": "Key " + $env.FAL_API_KEY, "Content-Type": "application/json" },
      body: JSON.stringify(payload)
    });
    if (resp.ok) {
      const result = await resp.json();
      if (!result.images || !result.images[0] || !result.images[0].url) {
        return { error: { shape: JSON.stringify(result).slice(0, 400) } };
      }
      return { url: result.images[0].url };
    }
    if (resp.status === 429 && attempt < retries) {
      const wait = 2000 * Math.pow(2, attempt - 1) + Math.floor(Math.random() * 1000);
      console.log("  callFal 429 on " + endpoint + " attempt " + attempt + "/" + retries + ", waiting " + wait + "ms");
      await new Promise(function(res) { setTimeout(res, wait); });
      continue;
    }
    let errText = "";
    try { errText = await resp.text(); } catch (_) {}
    return { error: { http: resp.status, body: errText.slice(0, 400) } };
  }
  return { error: { exhausted: true } };
}

try {
  if (useTextModel) {
    modelUsed = "fal-ai/recraft-v3";
    let r = await callFal("https://fal.run/fal-ai/recraft-v3", {
      prompt: promptIn,
      image_size: "landscape_16_9",
      style: "realistic_image"
    });
    if (r.error) {
      console.log("[" + targetLabel + "] recraft-v3 failed, falling back to ideogram-v2: " + JSON.stringify(r.error).slice(0, 200));
      modelUsed = "fal-ai/ideogram/v2/turbo";
      r = await callFal("https://fal.run/fal-ai/ideogram/v2/turbo", {
        prompt: promptIn,
        aspect_ratio: "16:9",
        style: "realistic"
      }, 1);
      if (r.error) throw new Error("Both text models failed: " + JSON.stringify(r.error).slice(0, 300));
      costUsd = 0.08;
    } else {
      costUsd = 0.04;
    }
    imageUrl = r.url;
  } else {
    modelUsed = "fal-ai/flux/schnell";
    const r = await callFal("https://fal.run/fal-ai/flux/schnell", {
      prompt: promptIn,
      negative_prompt: negativePrompt,
      image_size: "landscape_16_9",
      num_inference_steps: 4
    });
    if (r.error) throw new Error("Flux Schnell failed: " + JSON.stringify(r.error).slice(0, 300));
    imageUrl = r.url;
    costUsd = 0.003;
  }

  if (!imageUrl || typeof imageUrl !== "string") {
    throw new Error("Empty/invalid image_url returned by " + modelUsed);
  }
  if (!imageUrl.startsWith("http")) {
    throw new Error("Non-http image_url (" + imageUrl.slice(0, 80) + ") from " + modelUsed + " - refusing to persist");
  }
  if (sceneNumber > 0 && /scene_000\.png\b/.test(imageUrl)) {
    throw new Error("Filename collision guard tripped: scene " + sceneNumber + " got scene_000.png URL - payload likely missing scene_number");
  }
} catch (err) {
  providerError = err.message || String(err);
  console.log("[" + targetLabel + "] PROVIDER ERROR: " + providerError);
}

const elapsedMs = Date.now() - startTime;

// Persist resolved prompt + model + cost for provenance.
// Segments table has no image_prompt_resolved column, so write only model+cost when segment.
try {
  if (segmentId) {
    await fetch($env.SUPABASE_URL + "/rest/v1/scene_segments?id=eq." + segmentId, {
      method: "PATCH",
      headers: {
        "apikey": $env.SUPABASE_ANON_KEY,
        "Authorization": "Bearer " + $env.SUPABASE_SERVICE_ROLE_KEY,
        "Content-Type": "application/json",
        "Prefer": "return=minimal"
      },
      body: JSON.stringify({
        image_model: modelUsed,
        image_cost_usd: Math.round(costUsd * 100000) / 100000
      })
    });
  } else {
    await fetch($env.SUPABASE_URL + "/rest/v1/scenes?id=eq." + sceneId, {
      method: "PATCH",
      headers: {
        "apikey": $env.SUPABASE_ANON_KEY,
        "Authorization": "Bearer " + $env.SUPABASE_SERVICE_ROLE_KEY,
        "Content-Type": "application/json",
        "Prefer": "return=minimal"
      },
      body: JSON.stringify({
        image_prompt_resolved: promptIn.substring(0, 8000),
        image_model: modelUsed,
        image_cost_usd: Math.round(costUsd * 100000) / 100000
      })
    });
  }
} catch (e) { /* non-fatal */ }

// Append to production_log
try {
  await fetch($env.SUPABASE_URL + "/rest/v1/production_log", {
    method: "POST",
    headers: {
      "apikey": $env.SUPABASE_ANON_KEY,
      "Authorization": "Bearer " + $env.SUPABASE_SERVICE_ROLE_KEY,
      "Content-Type": "application/json",
      "Prefer": "return=minimal"
    },
    body: JSON.stringify({
      project_id: projectId,
      topic_id: topicId,
      stage: segmentId ? "image_segment" : "image",
      action: providerError ? "failed" : "completed",
      details: {
        scene_id: sceneId,
        scene_number: sceneNumber,
        segment_id: segmentId,
        segment_number: segmentNumber,
        model: modelUsed,
        prompt_resolved_preview: promptIn.substring(0, 600),
        prompt_length: promptIn.length,
        requires_text_flag: requiresTextFlag,
        route_reason: routeReason,
        used_text_model: useTextModel,
        cost_usd: costUsd,
        elapsed_ms: elapsedMs,
        error: providerError,
        image_url: imageUrl,
        register_id: body.register_id,
        color_mood: body.color_mood,
        zoom_direction: body.zoom_direction,
        composition_prefix: body.composition_prefix
      }
    })
  });
} catch (e) { /* non-fatal */ }

if (providerError) throw new Error("Image generation failed for " + targetLabel + ": " + providerError);

return [{ json: {
  scene_id: sceneId,
  scene_number: sceneNumber,
  segment_id: segmentId,
  segment_number: segmentNumber,
  image_url: imageUrl,
  model: modelUsed,
  cost_usd: costUsd,
  elapsed_ms: elapsedMs,
  image_status: "uploaded"
} }];
